"use client";

import {
  memo,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import { cn } from "@/lib/utils";
import {
  DEFAULT_STORY_VIEWER_LABELS,
  type StoryViewer01Handle,
  type StoryViewer01Labels,
  type StoryViewer01Props,
} from "./types";
import { useStoryViewerState } from "./hooks/use-story-viewer-state";
import { useStoryProgress } from "./hooks/use-story-progress";
import { useStoryKeyboardNav } from "./hooks/use-story-keyboard-nav";
import { useStoryEngagementState } from "./hooks/use-story-engagement-state";
import { ViewerShell } from "./parts/viewer-shell";
import { ProgressBars } from "./parts/progress-bars";
import { ViewerHeader } from "./parts/viewer-header";
import { TapZones } from "./parts/tap-zones";
import { NavArrows } from "./parts/nav-arrows";
import { ItemView } from "./parts/item-view";
import { EngagementOverlay } from "./parts/engagement-overlay";
import { buildStoryEngagementActionsWithMatrix } from "./lib/engagement-actions";

interface StoryViewer01InnerProps extends StoryViewer01Props {
  ref?: React.Ref<StoryViewer01Handle>;
}

function StoryViewer01Inner(props: StoryViewer01InnerProps) {
  const {
    stories: initialStories,
    initialStoryIndex,
    isOpen,
    onClose,
    ref,
    subscribe,
    onSubscribeDelta,
    onStoryViewed,
    onItemViewed,
    onCursorChange,
    onAutoCloseAtEnd,
    renderItem,
    defaultItemDuration = 5,
    labels: labelsProp,
    className,
    contentClassName,
    // v0.2.0 — engagement layer inputs (all optional; gated on viewerMode + !disableEngagement)
    viewerMode,
    permissions,
    canPerformAction,
    engagementSubscribe,
    onSubscribeEngagementDelta,
    onLikeStory,
    onReactStory,
    onShareStory,
    onBookmarkStory,
    reactionKinds,
    disableEngagement = false,
    renderEngagementOverlay,
  } = props;

  // v0.2.0 labels shape: required for all keys EXCEPT the nested forwards
  // (engagementLabels + commentLabels) which stay optional — hosts opt-in.
  const labels = useMemo<
    Required<Omit<StoryViewer01Labels, "engagementLabels" | "commentLabels">> &
      Pick<StoryViewer01Labels, "engagementLabels" | "commentLabels">
  >(
    () => ({ ...DEFAULT_STORY_VIEWER_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const {
    stories,
    cursor,
    isPaused,
    isMuted,
    setPaused,
    setMuted,
    goToPrevItem,
    goToNextItem,
    goToPrevStory,
    goToNextStory,
    goToStoryIndex,
    goToItemIndex,
    reset,
    dispatch,
  } = useStoryViewerState({
    initialStories,
    initialStoryIndex,
    isOpen,
    subscribe,
    onSubscribeDelta,
    onStoryViewed,
    onItemViewed,
    onCursorChange,
    onAutoCloseAtEnd,
    onClose,
  });

  const currentStory = stories[cursor.storyIndex];
  const currentItem = currentStory?.items[cursor.itemIndex];

  // Imperative handle.
  const storiesRef = useRef(stories);
  const cursorRef = useRef(cursor);
  useEffect(() => {
    storiesRef.current = stories;
    cursorRef.current = cursor;
  });
  useImperativeHandle(
    ref,
    () => ({
      // v0.1 (preserved)
      goToStory: goToStoryIndex,
      goToItem: goToItemIndex,
      setPaused: (paused: boolean) => setPaused(paused),
      getCursor: () => ({
        storyIndex: cursorRef.current.storyIndex,
        itemIndex: cursorRef.current.itemIndex,
      }),
      getCurrentStories: () => storiesRef.current,
      reset,
      dispatch,
      // v0.2.0 additions — stubbed no-ops in C1 (types-only commit). Real
      // implementations wire in C3 (triggerLike/triggerReaction/triggerShare
      // via engagement-overlay ref), C4 (triggerReply via composer ref + focus),
      // C6 (openKebab via kebab open state), and C10 (setMuted via setMuted setter).
      setMuted: (muted: boolean) => setMuted(muted),
      triggerLike: () => {},
      triggerReaction: (_kind?: string) => {},
      triggerReply: (_content?: string) => {},
      triggerShare: () => {},
      openKebab: () => {},
    }),
    [goToStoryIndex, goToItemIndex, setPaused, setMuted, reset, dispatch],
  );

  // Per-item video metadata duration cache.
  const [videoMetadataMs, setVideoMetadataMs] = useState<Record<string, number>>({});
  const handleVideoMetadata = useCallback(
    (duration: number) => {
      if (!currentItem) return;
      if (!Number.isFinite(duration) || duration <= 0) return;
      setVideoMetadataMs((prev) => {
        if (prev[currentItem.id] != null) return prev;
        return { ...prev, [currentItem.id]: duration * 1000 };
      });
    },
    [currentItem],
  );

  // Resolve item duration (R-Plan-4): explicit → video metadata → default.
  const itemDurationMs = useMemo(() => {
    if (!currentItem) return defaultItemDuration * 1000;
    if (currentItem.duration != null) return currentItem.duration * 1000;
    if (currentItem.type === "video") {
      const meta = videoMetadataMs[currentItem.id];
      if (meta != null) return meta;
    }
    return defaultItemDuration * 1000;
  }, [currentItem, videoMetadataMs, defaultItemDuration]);

  const itemKey = currentStory && currentItem
    ? `${currentStory.id}:${currentItem.id}`
    : "";

  const progress = useStoryProgress({
    isOpen: isOpen && !!currentItem,
    isPaused,
    itemKey,
    itemDurationMs,
    onComplete: goToNextItem,
  });

  // Keyboard nav (Escape funnels through Radix → onOpenChange).
  useStoryKeyboardNav({
    isOpen,
    onPrevItem: goToPrevItem,
    onNextItem: goToNextItem,
    onTogglePause: () => setPaused((p) => !p),
  });

  // ─── v0.2.0 engagement state (per-item like / reaction / reply counts) ──
  const { getState: getEngagementState, dispatch: dispatchEngagement } =
    useStoryEngagementState({
      subscribe: engagementSubscribe,
      onSubscribeDelta: onSubscribeEngagementDelta,
    });

  // Resolved engagement actions for the current item (rebuilt per cursor change)
  const engagementOverlayMounted =
    !!viewerMode && viewerMode === "viewer" && !disableEngagement && !!currentStory && !!currentItem;
  const engagementActions = useMemo(() => {
    if (!engagementOverlayMounted) return [];
    const state = getEngagementState(currentStory!.id, currentItem!.id);
    return buildStoryEngagementActionsWithMatrix({
      story: currentStory!,
      item: currentItem!,
      state,
      viewerMode,
      permissions,
      canPerformAction,
      reactionKinds,
      onLikeToggle: (next: boolean) => {
        dispatchEngagement({
          kind: "like-toggle",
          storyId: currentStory!.id,
          itemId: currentItem!.id,
          nextLiked: next,
        });
        onLikeStory?.(currentStory!.id, currentItem!.id, next);
      },
      onReactSelect: (kind: string | null) => {
        dispatchEngagement({
          kind: "reaction-select",
          storyId: currentStory!.id,
          itemId: currentItem!.id,
          reactionKind: kind,
        });
        onReactStory?.(currentStory!.id, currentItem!.id, kind);
      },
      onCommentClick: () => {
        // C4 will wire this to focus the reply composer; C3 stub
      },
      onShareClick: () => {
        onShareStory?.(currentStory!.id, currentItem!.id);
      },
      onBookmarkToggle: (next: boolean) => {
        onBookmarkStory?.(currentStory!.id, currentItem!.id, next);
      },
      // Kebab wired in C6
    });
  }, [
    engagementOverlayMounted,
    currentStory,
    currentItem,
    getEngagementState,
    viewerMode,
    permissions,
    canPerformAction,
    reactionKinds,
    dispatchEngagement,
    onLikeStory,
    onReactStory,
    onShareStory,
    onBookmarkStory,
  ]);

  const handleOpenChange = useCallback(
    (open: boolean) => {
      if (!open) onClose();
    },
    [onClose],
  );

  if (!currentStory || !currentItem) {
    // Render the shell so closing animations still fire when stories empty mid-view.
    return (
      <ViewerShell
        isOpen={isOpen}
        onOpenChange={handleOpenChange}
        ariaLabel={labels.viewerLabel}
        className={contentClassName}
      >
        <span />
      </ViewerShell>
    );
  }

  return (
    <ViewerShell
      isOpen={isOpen}
      onOpenChange={handleOpenChange}
      ariaLabel={labels.viewerLabel}
      className={contentClassName}
    >
      <NavArrows
        canPrev={cursor.storyIndex > 0}
        onPrev={goToPrevStory}
        onNext={goToNextStory}
        labels={labels}
      />

      <div className={cn("relative h-full w-full bg-black", className)}>
        <ProgressBars
          items={currentStory.items}
          currentItemIndex={cursor.itemIndex}
          progress={progress}
        />
        <ViewerHeader
          story={currentStory}
          item={currentItem}
          isPaused={isPaused}
          isMuted={isMuted}
          onTogglePause={() => setPaused((p) => !p)}
          onToggleMute={() => setMuted((m) => !m)}
          onClose={onClose}
          formatTime={labels.formatTime}
          labels={labels}
        />
        <ItemView
          item={currentItem}
          story={currentStory}
          totalItems={currentStory.items.length}
          cursor={cursor}
          isPaused={isPaused}
          isMuted={isMuted}
          onLoadedMetadata={handleVideoMetadata}
          onEnded={goToNextItem}
          renderItem={renderItem}
          labels={labels}
        />
        <TapZones
          onPrev={goToPrevItem}
          onTogglePause={() => setPaused((p) => !p)}
          onNext={goToNextItem}
        />

        {/* v0.2.0 — engagement overlay (TikTok/Reels-style stacked right edge).
            Renders only when viewerMode="viewer" + !disableEngagement.
            renderEngagementOverlay slot wins as full takeover. */}
        {engagementOverlayMounted ? (
          renderEngagementOverlay ? (
            renderEngagementOverlay(currentStory!, currentItem!, {
              cursor,
              isPaused,
              isMuted,
              setPaused: (p: boolean) => setPaused(p),
              setMuted: (m: boolean) => setMuted(m),
              goToPrevItem,
              goToNextItem,
              goToPrevStory,
              goToNextStory,
              onClose,
              labels,
            })
          ) : (
            <EngagementOverlay
              story={currentStory!}
              item={currentItem!}
              actions={engagementActions}
              labels={labels}
            />
          )
        ) : null}
      </div>
    </ViewerShell>
  );
}

const StoryViewer01 = memo(StoryViewer01Inner);
StoryViewer01.displayName = "StoryViewer01";

export { StoryViewer01 };

export { StoryViewer01 } from "./story-viewer-01";

export {
  storyViewerReducer,
  useStoryViewerState,
  type UseStoryViewerStateOptions,
  type UseStoryViewerStateResult,
} from "./hooks/use-story-viewer-state";

export {
  useStoryProgress,
  type UseStoryProgressOptions,
} from "./hooks/use-story-progress";

export {
  useStoryKeyboardNav,
  type UseStoryKeyboardNavOptions,
} from "./hooks/use-story-keyboard-nav";

export type {
  Story,
  StoryItem,
  StoryViewer01Props,
  StoryViewer01Handle,
  StoryViewer01Labels,
  StoryViewerDelta,
  StoryViewerLocalAction,
  RenderItemContext,
  Subscribe,
  Unsubscribe,
} from "./types";

export { DEFAULT_STORY_VIEWER_LABELS } from "./types";

import type { ElementType, ReactNode } from "react";

// ─── Data shapes ────────────────────────────────────────────────────────

/**
 * v0.2.0 — optional link CTA on a story item. Surfaces as a bottom button
 * (per Q-V9 lock). Custom CTA label via `cta`; otherwise defaults to
 * `labels.openLink` ("Open link").
 */
export interface StoryItemLink {
  url: string;
  /** Custom CTA label. Defaults to `labels.openLink`. */
  cta?: string;
}

export interface StoryItem {
  id: string;
  type: "image" | "video";
  src: string;
  /** Display duration in seconds. Default 5 for images; for videos, viewer reads the actual duration via onLoadedMetadata. */
  duration?: number;
  /**
   * v0.2.0 — optional link CTA rendered as a bottom button above the
   * engagement overlay. Polymorphic root via {@link StoryViewer01Props.linkComponent}.
   */
  link?: StoryItemLink;
}

/**
 * v0.2.0 — single viewer entry for the owner-mode viewers list. Relaxed
 * fields (parallel to engagement-bar-01's EngagementLikerProfile). Eager
 * seed via {@link Story.viewers}; lazy fetch via
 * {@link StoryViewer01Props.onLoadViewers}.
 */
export interface ViewerListItem {
  id: string;
  name: string;
  avatar?: string;
  /** ISO date of when this user viewed the story. Optional. */
  viewedAt?: string;
}

export interface Story {
  id: string;
  /** Stable user id — useful for cross-rail wiring. */
  userId: string;
  username: string;
  avatar?: string;
  items: StoryItem[];
  hasUnread?: boolean;
  /** ISO date string (matches the pro-ui convention from event-card-01 / content-card-news-01). */
  createdAt: string;
  /**
   * v0.2.0 — eager view count for the owner overlay. Cheap byte (single number);
   * the user list itself is lazy via {@link StoryViewer01Props.onLoadViewers}.
   */
  viewerCount?: number;
  /**
   * v0.2.0 — optional eager seed for the viewers list (hybrid Q-V5 lock). If
   * present, the owner overlay renders these immediately without waiting for
   * `onLoadViewers`. If absent, the overlay shows the count + a tap target that
   * triggers `onLoadViewers` on first expand.
   */
  viewers?: ViewerListItem[];
}

// ─── Realtime contract — viewer-state stream (v0.1.x; preserved) ─────────

export type Unsubscribe = () => void;
export type Subscribe<TDelta> = (handler: (delta: TDelta) => void) => Unsubscribe;

export type StoryViewerDelta =
  | { kind: "story-added"; story: Story; position?: "start" | "end" }
  | { kind: "story-removed"; storyId: string }
  | { kind: "item-added"; storyId: string; item: StoryItem; position?: "start" | "end" }
  | { kind: "item-removed"; storyId: string; itemId: string }
  | { kind: "story-viewed"; storyId: string };

export type StoryViewerLocalAction =
  | { kind: "add-story"; story: Story; position?: "start" | "end" }
  | { kind: "remove-story"; storyId: string }
  | { kind: "add-item"; storyId: string; item: StoryItem; position?: "start" | "end" }
  | { kind: "remove-item"; storyId: string; itemId: string }
  | { kind: "patch-story"; storyId: string; partial: Partial<Story> }
  | { kind: "subscribe-delta"; delta: StoryViewerDelta }
  | { kind: "reset"; next: Story[] };

// ─── v0.2.0 — engagement realtime (SEPARATE stream from StoryViewerDelta) ──
//
// Per Q-V3 lock: post-card-01 precedent has separate `engagementSubscribe` +
// `commentSubscribe` streams. story-viewer-01 mirrors with two streams:
// the existing `subscribe` (StoryViewerDelta — story-list mutations) and the
// new `engagementSubscribe` (StoryEngagementDelta — engagement events).
// Per Q-V16 lock: existing `subscribe` prop name preserved (asymmetric but
// zero v0.1 breakage).

export type StoryEngagementDelta =
  | { kind: "like-changed"; storyId: string; itemId: string; count: number; liked?: boolean }
  | { kind: "reaction-changed"; storyId: string; itemId: string; reactionKind?: string | null; count: number }
  | { kind: "reply-added"; storyId: string; itemId: string; replyId: string }
  | { kind: "viewer-added"; storyId: string; viewer: ViewerListItem }
  | { kind: "view-count-changed"; storyId: string; count: number };

export type StoryEngagementLocalAction =
  | { kind: "like-toggle"; storyId: string; itemId: string; nextLiked: boolean }
  | { kind: "reaction-select"; storyId: string; itemId: string; reactionKind: string | null }
  | { kind: "subscribe-delta"; delta: StoryEngagementDelta }
  | { kind: "reset"; storyId: string; itemId: string };

// ─── v0.2.0 — permissions (mirrors post-card-01 v0.3.0 resolver) ─────────
//
// Per Q-V10 lock: resolution order verbatim from post-card-01:
//   1. canPerformAction(action, story, item) returning true|false — wins
//   2. permissions[canX] per-field — false denies, true allows
//   3. viewerMode-derived defaults from PERMISSION_DEFAULTS_BY_MODE
//   4. (legacy v0.1 mode short-circuits in defaultStoryKebabActions when
//      all 3 role-aware inputs are undefined)

export type StoryViewerMode = "owner" | "viewer";

/**
 * Discriminator for the universal `canPerformAction` predicate.
 *
 * - Owner-side: `saveToHighlights`, `deleteStory`, `shareToFeed`, `seeViewers`
 * - Viewer-side: `react`, `reply`, `share`, `dm`, `report`, `blockAuthor`, `muteAuthor`
 * - Orthogonal: `moderate` (per Q-V11 lock — never auto-derived from viewerMode)
 */
export type StoryPermissionAction =
  | "saveToHighlights"
  | "deleteStory"
  | "shareToFeed"
  | "seeViewers"
  | "react"
  | "reply"
  | "share"
  | "dm"
  | "report"
  | "blockAuthor"
  | "muteAuthor"
  | "moderate";

/**
 * Per-action permissions matrix. Overrides the `viewerMode`-derived defaults.
 * Resolution order documented in {@link StoryViewerMode}.
 *
 * `canModerate` defaults to `false` in BOTH viewer modes — moderators must be
 * opted in explicitly by the host's permission resolver (mirrors post-card-01).
 *
 * Note: `canDM` casing intentional (DM as an acronym; not `canDm`). The
 * `actionToPermissionKey` helper in `lib/permissions.ts` special-cases this.
 */
export interface StoryViewerPermissions {
  // owner-side
  canSaveToHighlights?: boolean;
  canDeleteStory?: boolean;
  canShareToFeed?: boolean;
  canSeeViewers?: boolean;
  // viewer-side
  canReact?: boolean;
  canReply?: boolean;
  canShare?: boolean;
  canDM?: boolean;
  canReport?: boolean;
  canBlockAuthor?: boolean;
  canMuteAuthor?: boolean;
  // orthogonal (default false in BOTH modes — explicit-only, never auto-derived)
  canModerate?: boolean;
}

// ─── v0.2.0 — inline-copies from engagement-bar-01 (F-S1 Bug 3 fix) ──────
//
// engagement-bar-01 is in `data/` category; story-viewer-01 is in `media/`.
// Cross-category `/types` imports do NOT survive the shadcn 4.6.0 path
// rewriter (mangles to wrong-slug or invalid `<cat>/` prefix). Therefore
// these shapes are INLINE-COPIED — kept structurally identical to upstream.
//
// SYNC WARNING: if @ilinxa/engagement-bar-01 changes any of these shapes
// in a future bump, this file MUST be updated manually. The upstream
// definitions live at src/registry/components/data/engagement-bar-01/types.ts.

export type StoryEngagementActionAlign = "left" | "right" | "auto";

/**
 * Inlined from engagement-bar-01's `EngagementReactionKind` (v0.3.x).
 * Used by the reaction action in {@link StoryEngagementAction}.
 */
export interface StoryEngagementReactionKind {
  /** Stable identifier matching backend payloads (e.g. `"love"`, `"laugh"`). */
  key: string;
  /** Host-supplied icon node (lucide / emoji / image). Library does not ship reaction icons. */
  icon: ReactNode;
  /** Localized human label — used in picker tooltip + aria-label. */
  label: string;
  /** Seed tally for this kind. */
  count: number;
  /** Optional tint applied to the icon when this is the viewer's current reaction. */
  color?: string;
}

/**
 * Inlined from engagement-bar-01's `EngagementAction` discriminated union (v0.3.x).
 * Strict — no extra fields per kind.
 */
export type StoryEngagementAction =
  | {
      kind: "like";
      count: number;
      liked?: boolean;
      onToggle?: (next: boolean) => void;
      onCountClick?: () => void;
      align?: StoryEngagementActionAlign;
    }
  | {
      kind: "comment";
      count?: number;
      onClick?: () => void;
      align?: StoryEngagementActionAlign;
    }
  | {
      kind: "share";
      count?: number;
      onClick?: () => void;
      align?: StoryEngagementActionAlign;
    }
  | {
      kind: "bookmark";
      bookmarked?: boolean;
      onToggle?: (next: boolean) => void;
      align?: StoryEngagementActionAlign;
    }
  | {
      kind: "view-count";
      count: number;
      align?: StoryEngagementActionAlign;
    }
  | {
      kind: "custom";
      id: string;
      label: string;
      icon?: ReactNode;
      active?: boolean;
      onClick?: () => void;
      align?: StoryEngagementActionAlign;
    }
  | {
      kind: "reaction";
      kinds: StoryEngagementReactionKind[];
      viewerReaction?: string | null;
      onSelect?: (kind: string | null) => void;
      clearOnTap?: boolean;
      align?: StoryEngagementActionAlign;
    };

/**
 * Inlined from engagement-bar-01's `EngagementBarLabels` (v0.3.x; 13 keys).
 * Used as a nested forward inside {@link StoryViewer01Labels.engagementLabels}.
 */
export interface StoryEngagementBarLabels {
  like?: string;
  unlike?: string;
  openLikersPanel?: string;
  comment?: string;
  share?: string;
  bookmark?: string;
  unbookmark?: string;
  viewCount?: string;
  react?: string;
  removeReaction?: string;
  openReactionsPanel?: string;
  reactionPickerLabel?: string;
  formatCount?: (n: number) => string;
}

// ─── v0.2.0 — inline-copies from comment-thread-01 (F-S1 Bug 3 fix) ─────
//
// CommentThreadCurrentUser shape — small enough that a local minimal type
// matches the upstream contract structurally without needing the full inline-copy.
// CommentComposer is called directly from `parts/reply-composer.tsx` using
// its component import (cross-cat absolute-with-suffix path — works through
// the rewriter for components).

export interface StoryCurrentUser {
  id: string;
  name: string;
  avatar?: string;
}

/**
 * Inlined subset of CommentThreadLabels (the 3 composer-relevant keys).
 * Used as a nested forward inside {@link StoryViewer01Labels.commentLabels}.
 */
export interface StoryReplyComposerLabels {
  composerPlaceholder?: string;
  composerSend?: string;
  composerCancel?: string;
}

// ─── v0.2.0 — reactor list (parallel to viewers list) ────────────────────

export interface StoryReactorProfile {
  id: string;
  name?: string;
  avatar?: string;
  reactionKind?: string;
}

// ─── Render-prop helpers ────────────────────────────────────────────────

export interface RenderItemContext {
  storyIndex: number;
  itemIndex: number;
  isPaused: boolean;
  isMuted: boolean;
}

/**
 * v0.2.0 — shared helper context passed to all renderXxx slots (except renderItem).
 */
export interface StoryViewerSlotHelpers {
  cursor: { storyIndex: number; itemIndex: number };
  isPaused: boolean;
  isMuted: boolean;
  setPaused: (paused: boolean) => void;
  setMuted: (muted: boolean) => void;
  goToPrevItem: () => void;
  goToNextItem: () => void;
  goToPrevStory: () => void;
  goToNextStory: () => void;
  onClose: () => void;
  labels: ResolvedStoryViewer01Labels;
}

// ─── i18n ───────────────────────────────────────────────────────────────

export interface StoryViewer01Labels {
  // v0.1 (preserved)
  /** aria-label for the modal. Default: "Story viewer". */
  viewerLabel?: string;
  /** aria-label for the play button (when paused). Default: "Play". */
  play?: string;
  /** aria-label for the pause button (when playing). Default: "Pause". */
  pause?: string;
  /** aria-label for the mute button (when audio is on). Default: "Mute". */
  mute?: string;
  /** aria-label for the unmute button (when audio is off). Default: "Unmute". */
  unmute?: string;
  /** aria-label for the close button. Default: "Close". */
  close?: string;
  /** aria-label for the previous-story arrow. Default: "Previous story". */
  prevStory?: string;
  /** aria-label for the next-story arrow. Default: "Next story". */
  nextStory?: string;
  /** Format the relative time shown in the header. */
  formatTime?: (date: Date) => string;
  /** Default alt text for image items. */
  itemImageAlt?: (story: Story, itemIndex: number, totalItems: number) => string;

  // v0.2.0 — engagement overlay
  /** aria-label on the reaction picker popover. Default: "Pick a reaction". */
  reactionPickerLabel?: string;

  // v0.2.0 — reply composer
  /** Function so hosts can interpolate `${story.username}`. Default: `Reply to ${story.username}…`. */
  replyComposerPlaceholder?: (story: Story) => string;
  /** Default: "Send". */
  replyComposerSend?: string;
  /** Default: "Cancel". */
  replyComposerCancel?: string;

  // v0.2.0 — owner overlay
  /** Function so hosts can pluralize / localize. Default: `${count} views · ${time}`. */
  viewerCountLabel?: (count: number, time: string) => string;
  /** Default: "Viewers". */
  viewersHeading?: string;
  /** Function so hosts can pluralize. Default: `+${count} more`. */
  viewersMoreLabel?: (count: number) => string;

  // v0.2.0 — owner kebab
  /** Default: "Save to highlights". */
  saveToHighlights?: string;
  /** Default: "Remove from highlights". */
